sys_script_include.script:
var AROPCheckSeeder_HAM = Class.create();
AROPCheckSeeder_HAM.prototype = {
    initialize: function() {},
    getChecks: function() {
        return [{"module":"HAM","check_name":"Now Assist for HAM Plugin Status","order":"100","check_script":"(function() { var gr = new GlideRecord(\"sys_store_app\"); gr.addQuery(\"scope\", \"sn_now_assist_ham\"); gr.setLimit(1); gr.query(); if (gr.next()) { return { status: \"ready\", actualValue: \"Now Assist for Hardware Asset Management is active\", finding: \"Now Assist for HAM is active. AI-powered hardware asset lifecycle recommendations, refresh planning, and disposal insights are available.\" }; } var gr2 = new GlideRecord(\"sys_plugins\"); gr2.addQuery(\"id\", \"sn_now_assist_ham\"); gr2.addQuery(\"active\", true); gr2.setLimit(1); gr2.query(); if (gr2.next()) { return { status: \"ready\", actualValue: \"Now Assist for HAM is active\", finding: \"Now Assist for HAM is active. AI-powered hardware lifecycle management and refresh planning are available.\" }; } return { status: \"not_ready\", actualValue: \"Now Assist for HAM not found or inactive\", finding: \"Now Assist for HAM is not active. All AI-powered hardware asset management capabilities are unavailable without this plugin.\" }; })","ai_justification":"Now Assist for HAM is the foundational plugin enabling all AI capabilities for hardware asset lifecycle management including refresh recommendations and disposal insights. Without it no AI features are available regardless of data quality.","remediation_guidance":"Activate Now Assist for Hardware Asset Management via the ServiceNow Store. Confirm entitlement with your ServiceNow account team before activation.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Hardware Asset Volume","order":"200","check_script":"(function() { var ga = new GlideAggregate(\"alm_hardware\"); ga.addAggregate(\"COUNT\"); ga.query(); var total = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (total >= 500) { return { status: \"ready\", actualValue: total + \" hardware asset records\", finding: total + \" hardware assets. Now Assist HAM has sufficient asset data for AI-powered lifecycle analysis and refresh recommendations.\" }; } else if (total >= 100) { return { status: \"needs_attention\", actualValue: total + \" hardware asset records\", finding: \"Only \" + total + \" hardware assets (target: 500+). Now Assist HAM AI analysis will have limited coverage across the hardware estate.\" }; } else { return { status: \"not_ready\", actualValue: total + \" hardware asset records\", finding: \"Only \" + total + \" hardware assets. Insufficient data for meaningful Now Assist HAM AI lifecycle recommendations.\" }; } })","ai_justification":"Hardware asset volume determines the breadth of Now Assist HAM AI analysis. Without sufficient asset records, AI refresh recommendations and lifecycle insights are limited in scope and reliability.","remediation_guidance":"Ensure all hardware assets are tracked in ServiceNow. Import asset records from existing asset repositories or enable Discovery to automatically populate hardware asset records.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Hardware Asset Model Coverage","order":"300","check_script":"(function() { var gaTotal = new GlideAggregate(\"alm_hardware\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No hardware asset records found\", finding: \"No hardware asset records found. Model coverage cannot be assessed.\" }; } var gaModel = new GlideAggregate(\"alm_hardware\"); gaModel.addQuery(\"model\", \"!=\", \"\"); gaModel.addAggregate(\"COUNT\"); gaModel.query(); var withModel = gaModel.next() ? parseInt(gaModel.getAggregate(\"COUNT\")) : 0; var pct = Math.round((withModel / total) * 100); var actualValue = pct + \"% of hardware assets have a model (\" + withModel + \"/\" + total + \")\"; if (pct >= 90) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of hardware assets are linked to a model. Now Assist HAM has strong structured data for AI lifecycle analysis and refresh planning.\" }; } else if (pct >= 70) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of hardware assets have a model (target: 90%+). Now Assist HAM AI refresh recommendations will have reduced accuracy.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of hardware assets have a model. Insufficient structured data for meaningful Now Assist HAM AI lifecycle recommendations.\" }; } })","ai_justification":"Hardware models provide the structured product data Now Assist HAM uses for AI lifecycle analysis, end-of-life detection, and refresh recommendations. Without model coverage, AI cannot identify aging hardware or generate accurate replacement recommendations.","remediation_guidance":"Link all hardware assets to a model record. Use the Hardware Asset Workspace normalization tools to identify and map unmodeled assets. Model data is critical for AI lifecycle and refresh analysis.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Hardware Asset Assignment Rate","order":"400","check_script":"(function() { var gaTotal = new GlideAggregate(\"alm_hardware\"); gaTotal.addQuery(\"install_status\", \"1\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_applicable\", actualValue: \"No in-use hardware assets found\", finding: \"No hardware assets in use state. Assignment rate cannot be assessed.\" }; } var gaAssigned = new GlideAggregate(\"alm_hardware\"); gaAssigned.addQuery(\"install_status\", \"1\"); gaAssigned.addQuery(\"assigned_to\", \"!=\", \"\"); gaAssigned.addAggregate(\"COUNT\"); gaAssigned.query(); var assigned = gaAssigned.next() ? parseInt(gaAssigned.getAggregate(\"COUNT\")) : 0; var pct = Math.round((assigned / total) * 100); var actualValue = pct + \"% of in-use assets are assigned to a user (\" + assigned + \"/\" + total + \")\"; if (pct >= 90) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of in-use hardware assets have a user assignment. Now Assist HAM can accurately target refresh recommendations and reclamation candidates.\" }; } else if (pct >= 70) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of in-use assets have a user assignment (target: 90%+). Now Assist HAM AI reclamation and refresh targeting will be less accurate.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of in-use assets have a user assignment. Now Assist HAM cannot accurately target AI refresh recommendations without user assignment data.\" }; } })","ai_justification":"User assignment data enables Now Assist HAM to target AI refresh recommendations and reclamation candidates to the correct users and managers. Without assignment data, AI cannot determine who is using aging or underutilized assets.","remediation_guidance":"Assign all in-use hardware assets to their primary users. Navigate to Hardware Asset Management and bulk update assignment data. User assignment is critical for Now Assist HAM AI reclamation and refresh targeting.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Warranty Expiration Data","order":"500","check_script":"(function() { var gaTotal = new GlideAggregate(\"alm_hardware\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No hardware asset records found\", finding: \"No hardware asset records. Warranty data cannot be assessed.\" }; } var gaWarranty = new GlideAggregate(\"alm_hardware\"); gaWarranty.addQuery(\"warranty_expiration\", \"!=\", \"\"); gaWarranty.addAggregate(\"COUNT\"); gaWarranty.query(); var withWarranty = gaWarranty.next() ? parseInt(gaWarranty.getAggregate(\"COUNT\")) : 0; var pct = Math.round((withWarranty / total) * 100); var actualValue = pct + \"% of hardware assets have warranty expiration data (\" + withWarranty + \"/\" + total + \")\"; if (pct >= 80) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of hardware assets have warranty expiration dates. Now Assist HAM can generate AI-powered warranty risk alerts and proactive refresh recommendations.\" }; } else if (pct >= 50) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of assets have warranty expiration data (target: 80%+). Now Assist HAM AI warranty risk analysis will have incomplete coverage.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of assets have warranty expiration data. Now Assist HAM cannot generate meaningful AI warranty risk alerts without this data.\" }; } })","ai_justification":"Warranty expiration data is a primary signal Now Assist HAM uses for AI-powered proactive refresh recommendations and risk alerts. Without warranty dates, AI cannot identify assets approaching end of warranty or generate timely replacement recommendations.","remediation_guidance":"Populate warranty expiration dates on all hardware asset records. Import warranty data from procurement records or vendor portals. Navigate to Hardware Asset Management > Assets to bulk update warranty fields.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Financial Data Population","order":"600","check_script":"(function() { var gaTotal = new GlideAggregate(\"alm_hardware\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No hardware asset records found\", finding: \"No hardware asset records. Financial data cannot be assessed.\" }; } var gaFinancial = new GlideAggregate(\"alm_hardware\"); gaFinancial.addQuery(\"cost\", \">\", \"0\"); gaFinancial.addAggregate(\"COUNT\"); gaFinancial.query(); var withCost = gaFinancial.next() ? parseInt(gaFinancial.getAggregate(\"COUNT\")) : 0; var pct = Math.round((withCost / total) * 100); var actualValue = pct + \"% of hardware assets have cost data (\" + withCost + \"/\" + total + \")\"; if (pct >= 75) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of hardware assets have cost data. Now Assist HAM can generate AI-powered total cost of ownership analysis and financially-informed refresh recommendations.\" }; } else if (pct >= 40) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of assets have cost data (target: 75%+). Now Assist HAM AI financial analysis will have incomplete coverage.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of assets have cost data. Now Assist HAM cannot generate AI total cost of ownership analysis without financial data.\" }; } })","ai_justification":"Financial data enables Now Assist HAM to generate AI total cost of ownership analysis and financially-informed refresh recommendations. Without cost data, AI refresh recommendations lack the financial dimension needed to prioritize investments.","remediation_guidance":"Populate purchase cost on hardware asset records. Import financial data from procurement systems or ERP. Cost data is required for Now Assist HAM to generate AI-powered TCO analysis and financially-informed refresh prioritization.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"HAM Workspace Activation","order":"700","check_script":"(function() { var gr = new GlideRecord(\"sys_store_app\"); gr.addQuery(\"scope\", \"sn_ham_workspace\"); gr.setLimit(1); gr.query(); if (gr.next()) { return { status: \"ready\", actualValue: \"Hardware Asset Workspace is active\", finding: \"Hardware Asset Workspace is active. Now Assist HAM AI insights are surfaced in context for hardware asset managers.\" }; } var gr2 = new GlideRecord(\"sys_plugins\"); gr2.addQuery(\"id\", \"sn_ham_workspace\"); gr2.addQuery(\"active\", true); gr2.setLimit(1); gr2.query(); if (gr2.next()) { return { status: \"ready\", actualValue: \"Hardware Asset Workspace is active\", finding: \"Hardware Asset Workspace is active. Now Assist HAM AI lifecycle and refresh insights are available to asset managers.\" }; } return { status: \"not_ready\", actualValue: \"Hardware Asset Workspace not found or inactive\", finding: \"Hardware Asset Workspace is not active. Now Assist HAM AI insights are not accessible in a contextually relevant interface for hardware asset managers.\" }; })","ai_justification":"Hardware Asset Workspace is the primary interface where Now Assist HAM AI insights are presented to asset managers. Without it, AI-generated lifecycle recommendations and refresh plans are produced but never surfaced where asset managers work.","remediation_guidance":"Activate the Hardware Asset Workspace via the ServiceNow Store or Plugin Manager. The workspace is required for Now Assist HAM AI insights to surface in context for hardware asset managers.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Stockroom Configuration","order":"800","check_script":"(function() { var ga = new GlideAggregate(\"alm_stockroom\"); ga.addQuery(\"active\", true); ga.addAggregate(\"COUNT\"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (count >= 3) { return { status: \"ready\", actualValue: count + \" active stockrooms configured\", finding: count + \" active stockrooms. Now Assist HAM has structured inventory locations for AI-powered stock level analysis and procurement recommendations.\" }; } else if (count >= 1) { return { status: \"needs_attention\", actualValue: count + \" active stockroom(s) configured\", finding: \"Only \" + count + \" active stockroom(s) (target: 3+). Now Assist HAM AI stock analysis may not cover all inventory locations.\" }; } else { return { status: \"not_ready\", actualValue: \"No active stockrooms configured\", finding: \"No active stockrooms configured. Now Assist HAM cannot perform AI inventory level analysis or generate procurement recommendations without stockroom data.\" }; } })","ai_justification":"Stockroom configuration enables Now Assist HAM to analyze inventory levels across locations and generate AI-powered procurement and redistribution recommendations. Without stockrooms, AI cannot determine where assets are physically located or identify stock imbalances.","remediation_guidance":"Configure stockrooms for each physical location where hardware assets are stored. Navigate to Hardware Asset Management > Stockrooms to create and activate stockroom records.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"HAM Customization Risk","order":"900","check_script":"(function() { var ga = new GlideAggregate(\"sys_script\"); ga.addQuery(\"collection\", \"alm_hardware\"); ga.addQuery(\"active\", true); ga.addQuery(\"sys_created_by\", \"NOT IN\", \"glide.maint,system,admin,fred.luddy\"); ga.addAggregate(\"COUNT\"); ga.query(); var brs = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; var actualValue = brs + \" custom Business Rules on alm_hardware\"; if (brs <= 5) { return { status: \"ready\", actualValue: actualValue, finding: \"Low HAM customization risk (\" + brs + \" custom BRs). Now Assist HAM AI recommendations are unlikely to encounter conflicts with existing customizations.\" }; } else if (brs <= 10) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Moderate HAM customization risk (\" + brs + \" custom BRs). Test Now Assist HAM in sub-production before enabling in production.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"High HAM customization risk (\" + brs + \" custom BRs). Extensive customization increases the risk of conflicts with Now Assist HAM AI actions.\" }; } })","ai_justification":"Custom Business Rules on the hardware asset table can intercept or conflict with Now Assist HAM AI actions. High customization density increases the risk of AI recommendations failing or producing unexpected results.","remediation_guidance":"Review custom Business Rules on the alm_hardware table. Test Now Assist HAM in a sub-production environment to identify and resolve conflicts before enabling in production.","is_manual":"0","is_clone_sensitive":"0"},{"module":"HAM","check_name":"Asset Lifecycle Hygiene","order":"1000","check_script":"(function() { var gaTotal = new GlideAggregate(\"alm_hardware\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No hardware asset records found\", finding: \"No hardware asset records found.\" }; } // Count retired/disposed assets older than 2 years still in system var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-2); var gaStale = new GlideAggregate(\"alm_hardware\"); gaStale.addQuery(\"install_status\", \"IN\", \"7,9\"); gaStale.addQuery(\"sys_updated_on\", \"<\", cutoff.getValue()); gaStale.addAggregate(\"COUNT\"); gaStale.query(); var stale = gaStale.next() ? parseInt(gaStale.getAggregate(\"COUNT\")) : 0; var pct = Math.round((stale / total) * 100); var actualValue = stale + \" retired/disposed assets not updated in 2+ years (\" + pct + \"% of total)\"; if (pct <= 5) { return { status: \"ready\", actualValue: actualValue, finding: \"Low stale asset ratio (\" + pct + \"%). Asset lifecycle data is well maintained. Now Assist HAM AI analysis is based on current, accurate asset data.\" }; } else if (pct <= 15) { return { status: \"needs_attention\", actualValue: actualValue, finding: pct + \"% of assets are stale retired/disposed records. Now Assist HAM AI analysis accuracy will be reduced by outdated lifecycle data.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: pct + \"% of assets are stale retired/disposed records. Now Assist HAM AI recommendations will be unreliable with significant stale asset data contaminating the dataset.\" }; } })","ai_justification":"Asset lifecycle hygiene ensures Now Assist HAM AI analysis is based on current, accurate data. Stale retired and disposed records contaminate AI training data and skew lifecycle recommendations toward inaccurate conclusions.","remediation_guidance":"Archive or delete hardware asset records that have been retired or disposed for more than 2 years. Regular asset lifecycle hygiene ensures Now Assist HAM AI analysis is based on current, accurate data.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_HAM'
};
